SELECT factory_id, MAX(created_at) AS most_recent_note_timestamp
FROM system_notes
GROUP BY factory_id;

WITH DuplicateNotes AS (
    SELECT note
    FROM system_notes
    GROUP BY note
    HAVING COUNT(*) > 1
),
FilteredNotes AS (
    SELECT *
    FROM system_notes
    WHERE note LIKE '%parse%' 
      AND note LIKE '%large%' 
      AND note LIKE '%XML%'
      AND note IN (SELECT note FROM DuplicateNotes)
)
SELECT 
    fn.note_id AS ID,
    fn.factory_id AS FactoryID,
    fn.note AS Note,
    fn.created_at AS CreatedAt,
    PERCENT_RANK() OVER (PARTITION BY fn.factory_id ORDER BY fn.created_at) AS PercentileRank
FROM 
    FilteredNotes fn;

SELECT note 
FROM system_notes 
WHERE LENGTH(note) > 30 AND created_at > '2022-01-01';

SELECT MIN(created_at) AS earliest_note
FROM system_notes
WHERE created_at > '2022-01-01 00:00:00';

SELECT factory_id, created_at
FROM system_notes
WHERE created_at = (SELECT MIN(created_at) FROM system_notes);

SELECT PRINTF('The most recent note is from factory %d with the note ID %d', factory_id, note_id) AS 'Most Recent Note'
FROM system_notes
WHERE created_at = (SELECT MAX(created_at) FROM system_notes);

SELECT COUNT(DISTINCT factory_id) AS total_factories
FROM system_notes
WHERE note LIKE '%large XML%' AND created_at BETWEEN '2022-01-01' AND '2022-12-31';

SELECT DISTINCT factory_id
FROM system_notes
WHERE LOWER(note) LIKE '%factory%';

SELECT LTRIM(note) AS trimmed_note
FROM system_notes
WHERE note_id <= 1;

SELECT DISTINCT factory_id
FROM system_notes
ORDER BY factory_id;
